import type { RequestHandler } from "express";
import UserModel from "../models/user.js";

export type AuthedRequest = {
  userId: string;
  apiToken: string;
};

declare module "express-serve-static-core" {
  interface Request {
    employer?: AuthedRequest;
  }
}

export const verifyEmployerToken: RequestHandler = async (req, res, next) => {
  const raw = req.headers.authorization;
  if (!raw?.startsWith("Bearer ")) {
    return res.status(401).json({ error: "UNAUTHORIZED", message: "Missing Bearer token." });
  }
  const apiToken = raw.slice(7).trim();
  if (!apiToken) {
    return res.status(401).json({ error: "UNAUTHORIZED", message: "Empty token." });
  }
  const user = await UserModel.findOne({ apiToken }).select("_id").lean();
  if (!user) {
    return res.status(401).json({ error: "UNAUTHORIZED", message: "Invalid token." });
  }
  req.employer = { userId: String(user._id), apiToken };
  next();
};

import { randomBytes } from "node:crypto";

export function generateSubmissionToken(): string {
  return randomBytes(24).toString("base64url");
}

export function generateApiToken(): string {
  return `brk_${randomBytes(32).toString("base64url")}`;
}

import mongoose from "mongoose";

const UserSchema = new mongoose.Schema(
  {
    email: {
      type: String,
      required: true,
      unique: true,
      trim: true,
      lowercase: true,
      index: true,
    },
    companyName: { type: String, default: "", trim: true },
    /** Opaque bearer token for employer API (mini app — replace with Firebase in production). */
    apiToken: { type: String, required: true, unique: true, index: true },
