  body("assessmentId").isMongoId().withMessage("Invalid assessmentId"),
  body("candidateName").trim().notEmpty().isLength({ max: 200 }),
  body("displayName").optional().trim().isLength({ max: 200 }),
  body("candidateEmail").isEmail().normalizeEmail(),
